<?php/** * WooCommerce integration for AquaLuxe theme * * @package AquaLuxe *//** * Initialize WooCommerce integration */function aqualuxe_woocommerce_init() {    // Remove default WooCommerce styles    add_filter('woocommerce_enqueue_styles', '__return_empty_array');        // Add theme support for WooCommerce features    add_theme_support('woocommerce');    add_theme_support('wc-product-gallery-zoom');    add_theme_support('wc-product-gallery-lightbox');    add_theme_support('wc-product-gallery-slider');        // Set up hooks    add_action('after_setup_theme', 'aqualuxe_woocommerce_setup');        // Modify WooCommerce templates    add_filter('woocommerce_locate_template', 'aqualuxe_woocommerce_locate_template', 10, 3);        // Modify product loop    add_filter('loop_shop_per_page', 'aqualuxe_products_per_page');    add_filter('loop_shop_columns', 'aqualuxe_product_columns');        // Modify related products    add_filter('woocommerce_output_related_products_args', 'aqualuxe_related_products_args');        // Modify upsell products    add_filter('woocommerce_upsell_display_args', 'aqualuxe_upsell_products_args');        // Modify cross-sell products    add_filter('woocommerce_cross_sells_columns', 'aqualuxe_cross_sell_columns');    add_filter('woocommerce_cross_sells_total', 'aqualuxe_cross_sell_total');        // Add custom product tabs    add_filter('woocommerce_product_tabs', 'aqualuxe_product_tabs');        // Modify checkout fields    add_filter('woocommerce_checkout_fields', 'aqualuxe_checkout_fields');        // Modify account menu items    add_filter('woocommerce_account_menu_items', 'aqualuxe_account_menu_items');        // Add quick view functionality    if (get_theme_mod('aqualuxe_enable_quick_view', true)) {        add_action('aqualuxe_after_shop_loop_item', 'aqualuxe_quick_view_button');        add_action('wp_ajax_aqualuxe_quick_view', 'aqualuxe_quick_view_ajax');        add_action('wp_ajax_nopriv_aqualuxe_quick_view', 'aqualuxe_quick_view_ajax');        add_action('wp_footer', 'aqualuxe_quick_view_modal');    }        // Add wishlist functionality    if (get_theme_mod('aqualuxe_enable_wishlist', true)) {        add_action('aqualuxe_after_shop_loop_item', 'aqualuxe_wishlist_button');        add_action('wp_ajax_aqualuxe_wishlist_add', 'aqualuxe_wishlist_add_ajax');        add_action('wp_ajax_nopriv_aqualuxe_wishlist_add', 'aqualuxe_wishlist_add_ajax');        add_action('wp_ajax_aqualuxe_wishlist_remove', 'aqualuxe_wishlist_remove_ajax');        add_action('wp_ajax_nopriv_aqualuxe_wishlist_remove', 'aqualuxe_wishlist_remove_ajax');    }        // Add advanced filtering    add_action('woocommerce_before_shop_loop', 'aqualuxe_advanced_filtering', 30);        // Add multi-currency support    if (get_theme_mod('aqualuxe_enable_multi_currency', true)) {        add_action('aqualuxe_before_header', 'aqualuxe_currency_switcher');    }        // Optimize checkout for international shipping    add_filter('woocommerce_default_address_fields', 'aqualuxe_optimize_address_fields');    add_filter('woocommerce_shipping_calculator_enable_city', '__return_true');    add_filter('woocommerce_shipping_calculator_enable_postcode', '__return_true');        // Add order tracking enhancements    add_action('woocommerce_order_details_before_order_table', 'aqualuxe_order_tracking_info');        // Add custom product badges    add_action('woocommerce_before_shop_loop_item_title', 'aqualuxe_product_badges', 10);        // Add size guide    add_action('woocommerce_before_add_to_cart_form', 'aqualuxe_size_guide');        // Add estimated delivery time    add_action('woocommerce_after_add_to_cart_form', 'aqualuxe_estimated_delivery');        // Add product inquiry form    add_action('woocommerce_after_single_product_summary', 'aqualuxe_product_inquiry_form', 15);        // Add product social sharing    add_action('woocommerce_share', 'aqualuxe_product_sharing');        // Add recently viewed products    add_action('template_redirect', 'aqualuxe_track_product_view');    add_action('woocommerce_after_single_product', 'aqualuxe_recently_viewed_products');        // Add product video support    add_action('woocommerce_product_thumbnails', 'aqualuxe_product_video', 30);        // Add 360 degree product view    add_action('woocommerce_product_thumbnails', 'aqualuxe_product_360_view', 40);        // Add product specifications table    add_action('woocommerce_after_single_product_summary', 'aqualuxe_product_specifications', 12);        // Add product care instructions    add_action('woocommerce_after_single_product_summary', 'aqualuxe_product_care_instructions', 14);        // Add product reviews enhancement    add_filter('woocommerce_product_review_comment_form_args', 'aqualuxe_review_form_args');        // Add product comparison feature    add_action('aqualuxe_after_shop_loop_item', 'aqualuxe_compare_button');        // Add bulk discount information    add_action('woocommerce_before_add_to_cart_button', 'aqualuxe_bulk_discount_info');        // Add stock notification feature    add_action('woocommerce_after_add_to_cart_form', 'aqualuxe_stock_notification_form');        // Add product FAQ section    add_action('woocommerce_after_single_product_summary', 'aqualuxe_product_faq', 16);        // Add product warranty information    add_action('woocommerce_after_add_to_cart_form', 'aqualuxe_product_warranty_info');        // Add shipping information    add_action('woocommerce_after_add_to_cart_form', 'aqualuxe_shipping_info');        // Add return policy information    add_action('woocommerce_after_add_to_cart_form', 'aqualuxe_return_policy_info');        // Add product bundles support    add_action('woocommerce_after_single_product_summary', 'aqualuxe_product_bundles', 18);        // Add product customization options    add_action('woocommerce_before_add_to_cart_button', 'aqualuxe_product_customization_options');        // Add gift wrapping option    add_action('woocommerce_before_add_to_cart_button', 'aqualuxe_gift_wrapping_option');        // Add cart enhancements    add_action('woocommerce_before_cart', 'aqualuxe_cart_progress_bar');    add_action('woocommerce_cart_coupon', 'aqualuxe_cart_coupon_description');    add_action('woocommerce_after_cart_table', 'aqualuxe_cart_cross_sells_enhanced');        // Add checkout enhancements    add_action('woocommerce_checkout_before_customer_details', 'aqualuxe_checkout_steps');    add_action('woocommerce_review_order_before_payment', 'aqualuxe_checkout_trust_badges');        // Add order received enhancements    add_action('woocommerce_thankyou', 'aqualuxe_order_received_enhancements');        // Add account dashboard enhancements    add_action('woocommerce_account_dashboard', 'aqualuxe_account_dashboard_enhancements');}add_action('after_setup_theme', 'aqualuxe_woocommerce_init');